import React, { useEffect, useState } from 'react';
import { supabase } from '../services/supabaseClient.js';

const Listagem = () => {
  const [despesas, setDespesas] = useState([]);

  useEffect(() => {
    fetchDespesas();
  }, []);

  async function fetchDespesas() {
    const { data, error } = await supabase
      .from('compras')
      .select('*')
      .order('data_compra', { ascending: false });
    
    if (error) console.error('Erro:', error);
    else setDespesas(data);
  }

  return (
    <div className="fade-in"> {/* <--- Adicionado aqui */}
      <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '20px' }}>
        <h2>Minhas Despesas</h2>
        <span style={{ color: 'var(--text-muted)', fontSize: '0.9rem' }}>
          {despesas.length} registros encontrados
        </span>
      </div>

      <div className="card" style={{ padding: '0', overflowX: 'auto' }}>
  <table>
    <thead>
      <tr>
        <th>Data</th>
        <th>Descrição</th>
        <th>Loja</th>
        <th>Pedido/NF</th>
        <th>Parcelas</th>
        <th>Valor Total</th>
      </tr>
    </thead>
    <tbody>
      {despesas.map((item) => (
        <tr key={item.id}>
          <td>{new Date(item.data_compra).toLocaleDateString('pt-BR')}</td>
          <td style={{ fontWeight: '600' }}>{item.descricao}</td>
          <td>{item.loja || '-'}</td>
          <td>
            <div style={{ fontSize: '0.8rem', color: 'var(--text-muted)' }}>
              {item.pedido && <span>P: {item.pedido}</span>}
              {item.nota_fiscal && <span style={{ marginLeft: '8px' }}>NF: {item.nota_fiscal}</span>}
              {!item.pedido && !item.nota_fiscal && '-'}
            </div>
          </td>
          <td>
            <span style={{ 
              background: item.parcelado ? '#e0e7ff' : '#f1f5f9', 
              color: item.parcelado ? '#4338ca' : '#475569',
              padding: '4px 8px', 
              borderRadius: '6px', 
              fontSize: '0.85rem' 
            }}>
              {item.parcelado ? `${item.num_parcelas}x` : 'À vista'}
            </span>
          </td>
          <td style={{ fontWeight: 'bold', color: 'var(--text-main)' }}>
            R$ {parseFloat(item.valor_total).toLocaleString('pt-BR', { minimumFractionDigits: 2 })}
          </td>
        </tr>
      ))}
    </tbody>
  </table>
</div>
    </div>
  );

};

export default Listagem;
